INSERT INTO public.memorials (user_id, type, first_name, last_name, bio, birth_date, death_date, location, image_url, visibility, is_draft, tags, plan)
VALUES
  ('00000000-0000-0000-0000-000000000001', 'human', 'Marco', 'Bianchi', 'Marco was a beloved father, teacher, and musician from Florence. He spent his life inspiring young minds and playing the violin in local orchestras. His warmth and generosity touched everyone who knew him.', '1952-03-15', '2024-11-02', 'Florence, Italy', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=400&fit=crop&crop=face', 'public', false, ARRAY['father', 'musician', 'teacher'], 'free'),
  ('00000000-0000-0000-0000-000000000001', 'human', 'Elena', 'Rossi', 'Elena was a passionate botanist and loving grandmother. She cultivated the most beautiful garden in her neighborhood and was known for her homemade limoncello. Her laughter was contagious and her spirit unforgettable.', '1948-07-22', '2025-01-18', 'Naples, Italy', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=400&h=400&fit=crop&crop=face', 'public', false, ARRAY['grandmother', 'botanist', 'gardener'], 'free'),
  ('00000000-0000-0000-0000-000000000001', 'pet', 'Rex', '', 'Rex was the most loyal golden retriever a family could ask for. He loved long walks on the beach, chasing tennis balls, and cuddling on the couch. He was a true member of the family for 14 wonderful years.', '2010-05-10', '2024-09-30', 'Rome, Italy', 'https://images.unsplash.com/photo-1552053831-71594a27632d?w=400&h=400&fit=crop&crop=face', 'public', false, ARRAY['golden retriever', 'dog', 'loyal'], 'free');